import{_ as i,o as s,c as a,ag as t}from"./chunks/framework.CHQlKclR.js";const c=JSON.parse('{"title":"Tracking Wheels","description":"","frontmatter":{},"headers":[],"relativePath":"api/tracking-wheels.md","filePath":"api/tracking-wheels.md"}'),r={name:"api/tracking-wheels.md"};function n(o,e,l,h,d,p){return s(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="tracking-wheels" tabindex="-1">Tracking Wheels <a class="header-anchor" href="#tracking-wheels" aria-label="Permalink to &quot;Tracking Wheels&quot;">​</a></h1><p>The <code>vortex::tracking_wheel</code> class represents an encoder coupled with a wheel, used for secondary odometry tracking. This allows Vortex to maintain position even when the drivetrain wheels slip.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><p>Vortex supports three types of encoders:</p><ol><li><strong>ADI Quadrature Encoders</strong> (standard 3-wire).</li><li><strong>V5 Rotation Sensors</strong> (high-resolution smart port).</li><li><strong>ADI Expander Encoders</strong> (3-wire encoders plugged into a smart expander).</li></ol><h3 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Vortex/api.hpp&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 1. ADI Encoder on ports &#39;A&#39; and &#39;B&#39;, 2.75&quot; wheel, 6&quot; from center</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vortex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tracking_wheel</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> adiTracker</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;A&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;B&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.75</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 2. Rotation Sensor on Port 5 (reversed), 2.75&quot; wheel, 0&quot; from center (centered)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vortex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tracking_wheel</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rotationTracker</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.75</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 3. ADI Encoder on expander in Smart Port 2, ports &#39;C&#39; and &#39;D&#39;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vortex</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tracking_wheel</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> expandedTracker</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, {</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;C&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;D&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><h2 id="calibration-units" tabindex="-1">Calibration &amp; Units <a class="header-anchor" href="#calibration-units" aria-label="Permalink to &quot;Calibration &amp; Units&quot;">​</a></h2><h3 id="void-wheel-diameter-set-double-diameter" tabindex="-1"><code>void wheel_diameter_set(double diameter)</code> <a class="header-anchor" href="#void-wheel-diameter-set-double-diameter" aria-label="Permalink to &quot;`void wheel_diameter_set(double diameter)`&quot;">​</a></h3><p>Sets the diameter of the physical wheel in inches.</p><h3 id="void-ratio-set-double-ratio" tabindex="-1"><code>void ratio_set(double ratio)</code> <a class="header-anchor" href="#void-ratio-set-double-ratio" aria-label="Permalink to &quot;`void ratio_set(double ratio)`&quot;">​</a></h3><p>If your encoder is geared relative to the wheel, set the ratio here.</p><ul><li><strong>Example</strong>: If the wheel rotates twice for every 1 encoder rotation, the ratio is <code>0.5</code>.</li></ul><h3 id="void-ticks-per-rev-set-double-ticks" tabindex="-1"><code>void ticks_per_rev_set(double ticks)</code> <a class="header-anchor" href="#void-ticks-per-rev-set-double-ticks" aria-label="Permalink to &quot;`void ticks_per_rev_set(double ticks)`&quot;">​</a></h3><p>Sets the resolution of the encoder.</p><ul><li><strong>ADI Encoders</strong>: Default is <code>360</code>.</li><li><strong>Rotation Sensors</strong>: Default is <code>36000</code> (centidegrees).</li></ul><h2 id="member-functions" tabindex="-1">Member Functions <a class="header-anchor" href="#member-functions" aria-label="Permalink to &quot;Member Functions&quot;">​</a></h2><h3 id="double-get" tabindex="-1"><code>double get()</code> <a class="header-anchor" href="#double-get" aria-label="Permalink to &quot;`double get()`&quot;">​</a></h3><p>Returns the distance traveled by the tracking wheel in <strong>inches</strong>.</p><h3 id="double-get-raw" tabindex="-1"><code>double get_raw()</code> <a class="header-anchor" href="#double-get-raw" aria-label="Permalink to &quot;`double get_raw()`&quot;">​</a></h3><p>Returns the raw tick count of the encoder.</p><h3 id="void-reset" tabindex="-1"><code>void reset()</code> <a class="header-anchor" href="#void-reset" aria-label="Permalink to &quot;`void reset()`&quot;">​</a></h3><p>Resets the encoder position to zero.</p><h3 id="void-distance-to-center-set-double-dist" tabindex="-1"><code>void distance_to_center_set(double dist)</code> <a class="header-anchor" href="#void-distance-to-center-set-double-dist" aria-label="Permalink to &quot;`void distance_to_center_set(double dist)`&quot;">​</a></h3><p>Updates the offset from the robot&#39;s tracking center. This is critical for accurate arc-based odometry.</p><ul><li><strong>Positive</strong>: Right of center (for vertical wheels) or Forward of center (for horizontal wheels).</li><li><strong>Negative</strong>: Left of center (for vertical wheels) or Backward of center (for horizontal wheels).</li></ul>',26)])])}const g=i(r,[["render",n]]);export{c as __pageData,g as default};
